// // This module concatenates two one-bit inputs In0 and In1 to produce a two-bit output dout. The most significant bit of dout is assigned the value of In0, while the least significant bit is assigned the value of In1.
module top_module(
  In0,
  In1,
  dout
);input wire [0 : 0] In0;
input wire [0 : 0] In1;
output wire [1 : 0] dout;

assign dout[0] = In0;
assign dout[1] = In1;

endmodule
